import React from 'react';
import {
    Box,
    Card,
    CardContent,
    Typography,
    LinearProgress,
    Table,
    TableBody,
    TableCell,
    TableContainer,
    TableHead,
    TableRow,
    Paper,
} from '@material-ui/core';
import AssignmentIcon from '@material-ui/icons/Assignment';
import TrendingUpIcon from '@material-ui/icons/TrendingUp';
import SecurityIcon from '@material-ui/icons/Security';
import { AnalysisResult, ModelMetrics, AttackStatistics } from '../types';

interface AnalysisResultsProps {
    analysisResult?: AnalysisResult;
    metrics?: ModelMetrics;
    statistics?: AttackStatistics;
}

const StatCard: React.FC<{
    icon: React.ReactNode;
    title: string;
    value: string | number;
    subtext?: string;
    color: string;
}> = ({ icon, title, value, subtext, color }) => (
    <Card
        sx={{
            height: '100%',
            background: `linear-gradient(135deg, ${color}20 0%, ${color}10 100%)`,
            border: `1px solid ${color}40`,
            transition: 'transform 0.3s, box-shadow 0.3s',
            '&:hover': {
                transform: 'translateY(-4px)',
                boxShadow: `0 8px 24px ${color}30`,
            },
        }}
    >
        <CardContent sx={{ textAlign: 'center' }}>
            <Box sx={{ color, mb: 1 }}>{icon}</Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
                {title}
            </Typography>
            <Typography variant="h5" sx={{ fontWeight: 'bold', color, mb: 1 }}>
                {value}
            </Typography>
            {subtext && (
                <Typography variant="caption" color="text.secondary">
                    {subtext}
                </Typography>
            )}
        </CardContent>
    </Card>
);

const MetricBar: React.FC<{ label: string; value: number; color: string }> = ({
    label,
    value,
    color,
}) => (
    <Box sx={{ mb: 3 }}>
        <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
            <Typography variant="body2" sx={{ fontWeight: 'bold' }}>
                {label}
            </Typography>
            <Typography variant="body2" sx={{ color, fontWeight: 'bold' }}>
                {(value * 100).toFixed(2)}%
            </Typography>
        </Box>
        <LinearProgress
            variant="determinate"
            value={value * 100}
            sx={{
                height: 8,
                borderRadius: 4,
                backgroundColor: '#e0e0e0',
                '& .MuiLinearProgress-bar': {
                    background: `linear-gradient(90deg, ${color} 0%, ${color}80 100%)`,
                    borderRadius: 4,
                },
            }}
        />
    </Box>
);

const AnalysisResults: React.FC<AnalysisResultsProps> = ({
    analysisResult,
    metrics,
    statistics,
}) => {
    if (!analysisResult && !metrics && !statistics) {
        return (
            <Box sx={{ textAlign: 'center', py: 6 }}>
                <AssignmentIcon sx={{ fontSize: 48, color: '#ccc', mb: 2 }} />
                <Typography variant="body1" color="text.secondary">
                    No analysis results available. Please upload and analyze a dataset first.
                </Typography>
            </Box>
        );
    }

    return (
        <Box>
            {/* Key Metrics Cards */}
            <Box sx={{ display: 'grid', gridTemplateColumns: { xs: '1fr', sm: '1fr 1fr', md: '1fr 1fr 1fr 1fr' }, gap: 2, mb: 4 }}>
                {analysisResult && (
                    <>
                        <StatCard
                            icon={<AssignmentIcon sx={{ fontSize: 32 }} />}
                            title="Total Records"
                            value={analysisResult.total_records}
                            color="#667eea"
                        />
                        <StatCard
                            icon={<SecurityIcon sx={{ fontSize: 32 }} />}
                            title="Attacks Detected"
                            value={analysisResult.attacks_detected}
                            subtext={`${analysisResult.attack_percentage}% of data`}
                            color="#f44336"
                        />
                        <StatCard
                            icon={<TrendingUpIcon sx={{ fontSize: 32 }} />}
                            title="Normal Records"
                            value={analysisResult.normal_records}
                            subtext={`${(100 - analysisResult.attack_percentage).toFixed(2)}% of data`}
                            color="#4caf50"
                        />
                        <StatCard
                            icon={<TrendingUpIcon sx={{ fontSize: 32 }} />}
                            title="Attack Rate"
                            value={`${analysisResult.attack_percentage}%`}
                            color="#ff9800"
                        />
                    </>
                )}
            </Box>

            {/* Model Metrics */}
            {metrics && (
                <Card sx={{ mb: 4, background: 'rgba(102, 126, 234, 0.05)', border: '1px solid rgba(102, 126, 234, 0.2)' }}>
                    <CardContent>
                        <Typography variant="h6" sx={{ fontWeight: 'bold', mb: 3 }}>
                            Model Performance Metrics
                        </Typography>
                        <MetricBar label="Accuracy" value={metrics.accuracy} color="#667eea" />
                        <MetricBar label="Precision" value={metrics.precision} color="#764ba2" />
                        <MetricBar label="Recall" value={metrics.recall} color="#f093fb" />
                        <MetricBar label="F1 Score" value={metrics.f1_score} color="#26a69a" />
                    </CardContent>
                </Card>
            )}

            {/* Attack Statistics */}
            {statistics && (
                <Card sx={{ background: 'rgba(244, 67, 54, 0.05)', border: '1px solid rgba(244, 67, 54, 0.2)' }}>
                    <CardContent>
                        <Typography variant="h6" sx={{ fontWeight: 'bold', mb: 3 }}>
                            Attack Statistics
                        </Typography>

                        <Box sx={{ mb: 3, p: 2, backgroundColor: '#fff', borderRadius: 1, border: '1px solid #e0e0e0' }}>
                            <Typography variant="body2" color="text.secondary">
                                Detection Rate
                            </Typography>
                            <Typography variant="h5" sx={{ color: '#f44336', fontWeight: 'bold' }}>
                                {statistics.detection_rate}%
                            </Typography>
                        </Box>

                        <Typography variant="subtitle2" sx={{ fontWeight: 'bold', mb: 2 }}>
                            Attack Types Breakdown:
                        </Typography>

                        {Object.keys(statistics.attack_types).length > 0 ? (
                            <TableContainer component={Paper} sx={{ backgroundColor: '#fafafa' }}>
                                <Table size="small">
                                    <TableHead sx={{ backgroundColor: '#f5f3ff' }}>
                                        <TableRow>
                                            <TableCell sx={{ fontWeight: 'bold', color: '#667eea' }}>Attack Type</TableCell>
                                            <TableCell align="right" sx={{ fontWeight: 'bold', color: '#667eea' }}>
                                                Count
                                            </TableCell>
                                            <TableCell align="right" sx={{ fontWeight: 'bold', color: '#667eea' }}>
                                                Percentage
                                            </TableCell>
                                        </TableRow>
                                    </TableHead>
                                    <TableBody>
                                        {Object.entries(statistics.attack_types).map(([type, count]) => {
                                            const percentage =
                                                statistics.attacks_detected > 0
                                                    ? ((count / statistics.attacks_detected) * 100).toFixed(2)
                                                    : 0;
                                            return (
                                                <TableRow key={type} hover sx={{ '&:last-child td': { border: 0 } }}>
                                                    <TableCell sx={{ fontWeight: 500 }}>{type}</TableCell>
                                                    <TableCell align="right">{count}</TableCell>
                                                    <TableCell align="right">
                                                        <Box
                                                            sx={{
                                                                display: 'inline-block',
                                                                px: 1.5,
                                                                py: 0.5,
                                                                backgroundColor: '#f4433620',
                                                                color: '#f44336',
                                                                borderRadius: 1,
                                                                fontWeight: 'bold',
                                                                fontSize: '0.875rem',
                                                            }}
                                                        >
                                                            {percentage}%
                                                        </Box>
                                                    </TableCell>
                                                </TableRow>
                                            );
                                        })}
                                    </TableBody>
                                </Table>
                            </TableContainer>
                        ) : (
                            <Typography variant="body2" color="text.secondary">
                                No specific attack types detected in the dataset.
                            </Typography>
                        )}
                    </CardContent>
                </Card>
            )}
        </Box>
    );
};

export default AnalysisResults;
